+import { NextRequest } from "next/server";
+import { jsonResponse } from "@/app/api/response";
+import { extractUser } from "@/app/api/request";
+import { appPrisma } from "@/app/utils/db";
+import { USER_PLAN_STATUSES, type UserPlanStatus } from "@/app/constants/plans";
+
+/**
+ * PATCH /api/plans/:planId — change enrollment status (pause/resume/complete/
+ * abandon). Ownership is re-verified server-side; the id in the URL is not a
+ * capability. Body: { status }.
+ */
+export async function PATCH(
+  request: NextRequest,
+  { params }: { params: { planId: string } }
+) {
+  const user = extractUser(request);
+  if (!user) return jsonResponse({ code: 401, message: "Unauthorized" });
+
+  const planId = Number(params.planId);
+  if (!Number.isInteger(planId)) {
+    return jsonResponse({ code: 422, message: "Invalid plan id" });
+  }
+
+  const body = await request.json().catch(() => null);
+  const status = body?.status as UserPlanStatus | undefined;
+  if (!status || !USER_PLAN_STATUSES.includes(status)) {
+    return jsonResponse({ code: 422, message: "Invalid status" });
+  }
+
+  const plan = await appPrisma.userPlan.findUnique({ where: { id: planId } });
+  if (!plan || plan.user_id !== user.id) {
+    return jsonResponse({ code: 404, message: "Plan not found" });
+  }
+
+  const updated = await appPrisma.userPlan.update({
+    where: { id: planId },
+    data: { status },
+  });
+
+  return jsonResponse({ data: { id: updated.id, status: updated.status } });
+}
diff --git a/app/api/plans/route.ts b/app/api/plans/route.ts
new file mode 100644
index 0000000..8c1999e
--- /dev/null
+++ b/app/api/plans/route.ts
@@ -0,0 +1,94 @@
+import { NextRequest } from "next/server";
+import { jsonResponse } from "@/app/api/response";
+import { extractUser } from "@/app/api/request";
+import { appPrisma } from "@/app/utils/db";
+import {
+  PLAN_DATE_RE,
+  getPlanTemplate,
+  type UserPlanParams,
+  type UserPlanStatus,
+} from "@/app/constants/plans";
+
+export type UserPlanListItem = {
+  id: number;
+  template_key: string;
+  params: UserPlanParams;
+  start_date: string;
+  status: UserPlanStatus;
+};
+
+export const toDateString = (d: Date) => d.toISOString().slice(0, 10);
+
+const serializePlan = (plan: {
+  id: number;
+  template_key: string;
+  params: unknown;
+  start_date: Date;
+  status: string;
+}): UserPlanListItem => ({
+  id: plan.id,
+  template_key: plan.template_key,
+  params: (plan.params ?? {}) as UserPlanParams,
+  start_date: toDateString(plan.start_date),
+  status: plan.status as UserPlanStatus,
+});
+
+/** GET /api/plans — the caller's enrollments (all statuses). Protected. */
+export async function GET(request: NextRequest) {
+  const user = extractUser(request);
+  if (!user) return jsonResponse({ code: 401, message: "Unauthorized" });
+
+  const plans = await appPrisma.userPlan.findMany({
+    where: { user_id: user.id },
+    orderBy: { created_at: "desc" },
+  });
+
+  return jsonResponse({ data: plans.map(serializePlan) });
+}
+
+/**
+ * POST /api/plans — enroll in a template. Multiple concurrent active
+ * enrollments are allowed (D6). Body: { template_key, params?, start_date? }.
+ */
+export async function POST(request: NextRequest) {
+  const user = extractUser(request);
+  if (!user) return jsonResponse({ code: 401, message: "Unauthorized" });
+
+  const body = await request.json().catch(() => null);
+  if (!body?.template_key) {
+    return jsonResponse({ code: 422, message: "Missing template_key" });
+  }
+
+  const template = getPlanTemplate(body.template_key);
+  if (!template) {
+    return jsonResponse({ code: 422, message: "Unknown template_key" });
+  }
+
+  if (body.start_date && !PLAN_DATE_RE.test(body.start_date)) {
+    return jsonResponse({ code: 422, message: "Invalid start_date" });
+  }
+
+  const params: UserPlanParams = body.params ?? {};
+  if (params.endDate && !PLAN_DATE_RE.test(params.endDate)) {
+    return jsonResponse({ code: 422, message: "Invalid params.endDate" });
+  }
+  if (template.missedDayPolicy === "calendar" && !params.endDate) {
+    return jsonResponse({
+      code: 422,
+      message: "This template requires params.endDate",
+    });
+  }
+
+  const startDate = body.start_date ?? toDateString(new Date());
+
+  const plan = await appPrisma.userPlan.create({
+    data: {
+      user_id: user.id,
+      template_key: template.key,
+      params: params as object,
+      start_date: new Date(`${startDate}T00:00:00Z`),
+    },
+  });
+
+  return jsonResponse({ data: serializePlan(plan) });
+}
diff --git a/app/api/plans/today/route.ts b/app/api/plans/today/route.ts
new file mode 100644
index 0000000..98dce16
--- /dev/null
+++ b/app/api/plans/today/route.ts
@@ -0,0 +1,70 @@
+import { NextRequest } from "next/server";
+import { jsonResponse } from "@/app/api/response";
+import { extractUser } from "@/app/api/request";
+import { appPrisma } from "@/app/utils/db";
+import {
+  PLAN_DATE_RE,
+  getPlanTemplate,
+  type UserPlanParams,
+} from "@/app/constants/plans";
+import {
+  deriveAssignments,
+  type ProgressLogEntry,
+  type TrackAssignment,
+} from "@/app/lib/plans/engine";
+
+export type TodayPlanAssignments = {
+  planId: number;
+  templateKey: string;
+  assignments: TrackAssignment[];
+};
+
+/**
+ * GET /api/plans/today?date=YYYY-MM-DD — derived assignments for every active
+ * enrollment on the given local date (client supplies its local-midnight day,
+ * ADR 0028). Nothing is stored — pure derivation from the progress log.
+ */
+export async function GET(request: NextRequest) {
+  const user = extractUser(request);
+  if (!user) return jsonResponse({ code: 401, message: "Unauthorized" });
+
+  const date = request.nextUrl.searchParams.get("date");
+  if (!date || !PLAN_DATE_RE.test(date)) {
+    return jsonResponse({ code: 422, message: "Missing or invalid date" });
+  }
+
+  const plans = await appPrisma.userPlan.findMany({
+    where: { user_id: user.id, status: "active" },
+    include: { progress: true },
+    orderBy: { created_at: "asc" },
+  });
+
+  const data: TodayPlanAssignments[] = [];
+
+  for (const plan of plans) {
+    const template = getPlanTemplate(plan.template_key);
+    // An enrollment referencing a template this build no longer ships is
+    // skipped, not an error — templates are code (ADR 0028).
+    if (!template) continue;
+
+    const entries: ProgressLogEntry[] = plan.progress.map((entry) => ({
+      track_key: entry.track_key,
+      date: entry.date.toISOString().slice(0, 10),
+      range_start: entry.range_start,
+      range_end: entry.range_end,
+    }));
+
+    data.push({
+      planId: plan.id,
+      templateKey: plan.template_key,
+      assignments: deriveAssignments(
+        template,
+        (plan.params ?? {}) as UserPlanParams,
+        entries,
+        date
+      ),
+    });
+  }
+
+  return jsonResponse({ data });
+}
diff --git a/app/constants/plans.ts b/app/constants/plans.ts
new file mode 100644
index 0000000..b8da10f
--- /dev/null
+++ b/app/constants/plans.ts
@@ -0,0 +1,129 @@
+/**
+ * Plan engine template definitions (ADR 0028).
+ *
+ * Templates are typed TS constants (like MARK_CATEGORIES) — never DB rows.
+ * A track = unit + quantity + one scheduling rule kind + an activity.
+ * Scheduling ("which range today?") is orthogonal to activity ("what you do
+ * with it") — never encode modality into a rule kind.
+ *
+ * All ranges are page-canonical (mushaf pages 1–604), inclusive on both ends.
+ */
+
+export const MUSHAF_FIRST_PAGE = 1;
+export const MUSHAF_LAST_PAGE = 604;
+
+/** Validates "YYYY-MM-DD" date strings used across the plan APIs. */
+export const PLAN_DATE_RE = /^\d{4}-\d{2}-\d{2}$/;
+
+export const PLAN_ACTIVITIES = ["read", "listen", "memorize", "review"] as const;
+export type PlanActivity = (typeof PLAN_ACTIVITIES)[number];
+
+/** v1 is page-canonical; "verse" is the planned future widening (D3). */
+export type PlanUnit = "page";
+
+export type TrackRule =
+  | {
+      /** Cycle a fixed range at N units/day, wrap on completion (khatma). */
+      kind: "fixed_cycle";
+      rangeStart: number;
+      rangeEnd: number;
+      defaultUnitsPerDay: number;
+    }
+  | {
+      /** Advance a cursor N units/day through a target range; stops at end. */
+      kind: "cursor_advance";
+      defaultUnitsPerDay: number;
+    }
+  | {
+      /** Re-visit the last `windowSize` units completed by `sourceTrack`. */
+      kind: "trailing_window";
+      sourceTrack: string;
+      windowSize: number;
+    }
+  | {
+      /**
+       * Cycle N units/day through everything `sourceTrack` has completed,
+       * excluding its most recent `excludeTrailingWindow` units (those belong
+       * to the near-review track).
+       */
+      kind: "completed_cycle";
+      sourceTrack: string;
+      defaultUnitsPerDay: number;
+      excludeTrailingWindow: number;
+    }
+  | {
+      /** Preview tomorrow's assignment of `sourceTrack`, × repetitions. */
+      kind: "lookahead";
+      sourceTrack: string;
+      repetitions: number;
+    };
+
+export type PlanTrack = {
+  key: string;
+  activity: PlanActivity;
+  unit: PlanUnit;
+  rule: TrackRule;
+};
+
+/**
+ * Missed-day policy (D4): "cursor" — the plan shifts forward, tomorrow resumes
+ * where you stopped; "calendar" — a fixed end date, remaining quantity is
+ * recomputed over remaining days (requires params.endDate).
+ */
+export type MissedDayPolicy = "cursor" | "calendar";
+
+export type PlanTemplate = {
+  key: string;
+  tracks: PlanTrack[];
+  missedDayPolicy: MissedDayPolicy;
+};
+
+/**
+ * Per-enrollment configuration stored in UserPlan.params (JSON).
+ * quantities override a track rule's defaultUnitsPerDay by track key.
+ * targetStart/targetEnd bound cursor_advance tracks (e.g. "memorize Juz Amma").
+ * endDate ("YYYY-MM-DD") is required by the "calendar" missed-day policy.
+ */
+export type UserPlanParams = {
+  quantities?: Record<string, number>;
+  startPage?: number;
+  targetStart?: number;
+  targetEnd?: number;
+  endDate?: string;
+};
+
+export const USER_PLAN_STATUSES = [
+  "active",
+  "paused",
+  "completed",
+  "abandoned",
+] as const;
+export type UserPlanStatus = (typeof USER_PLAN_STATUSES)[number];
+
+/**
+ * The launch template: the original ask — read N pages/day through the whole
+ * mushaf. الحصون الخمسة ships later as a 5-track template composing all five
+ * rule kinds, once its per-level quantities are sourced (see the plan doc).
+ */
+export const PLAN_TEMPLATES: Record<string, PlanTemplate> = {
+  "daily-wird": {
+    key: "daily-wird",
+    missedDayPolicy: "cursor",
+    tracks: [
+      {
+        key: "reading",
+        activity: "read",
+        unit: "page",
+        rule: {
+          kind: "fixed_cycle",
+          rangeStart: MUSHAF_FIRST_PAGE,
+          rangeEnd: MUSHAF_LAST_PAGE,
+          defaultUnitsPerDay: 5,
+        },
+      },
+    ],
+  },
+};
+
+export const getPlanTemplate = (key: string): PlanTemplate | null =>
+  PLAN_TEMPLATES[key] ?? null;
diff --git a/app/hooks/use-plans.ts b/app/hooks/use-plans.ts
